package com.example.fileupload;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.ServerInterceptors;
import io.grpc.netty.shaded.io.grpc.netty.NettyServerBuilder;
import io.grpc.netty.shaded.io.netty.channel.ChannelOption;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

public class GrpcServer {
    private Server server;

    public void start() throws IOException {
        int port = 50051;
        
        FileUploadServiceImpl service = new FileUploadServiceImpl();
        
        server = NettyServerBuilder.forPort(port)
            .addService(ServerInterceptors.intercept(service, new RateLimitInterceptor()))
            .maxInboundMessageSize(MAX_CHUNK_SIZE + 1024) // Chunk size + metadata overhead
            .maxInboundMetadataSize(8 * 1024) // 8KB metadata limit
            .maxConnectionIdle(5, TimeUnit.MINUTES)
            .maxConnectionAge(30, TimeUnit.MINUTES)
            .maxConnectionAgeGrace(5, TimeUnit.MINUTES)
            .permitKeepAliveTime(5, TimeUnit.MINUTES)
            .permitKeepAliveWithoutCalls(false)
            .withChildOption(ChannelOption.SO_KEEPALIVE, true)
            .build()
            .start();

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            try {
                GrpcServer.this.stop();
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }));
    }

    private static final int MAX_CHUNK_SIZE = 1024 * 1024;

    public void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        final GrpcServer server = new GrpcServer();
        server.start();
        server.blockUntilShutdown();
    }
}

// RateLimitInterceptor.java
package com.example.fileupload;

import io.grpc.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

public class RateLimitInterceptor implements ServerInterceptor {
    private static final int MAX_REQUESTS_PER_MINUTE = 100;
    private final ConcurrentHashMap<String, RateLimitBucket> rateLimits = new ConcurrentHashMap<>();

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        String clientId = getClientIdentifier(call, headers);
        
        RateLimitBucket bucket = rateLimits.computeIfAbsent(clientId, k -> new RateLimitBucket());
        
        if (!bucket.allowRequest()) {
            call.close(Status.RESOURCE_EXHAUSTED.withDescription("Rate limit exceeded"), new Metadata());
            return new ServerCall.Listener<ReqT>() {};
        }

        return next.startCall(call, headers);
    }

    private <ReqT, RespT> String getClientIdentifier(ServerCall<ReqT, RespT> call, Metadata headers) {
        String authority = call.getAuthority();
        return authority != null ? authority : "unknown";
    }

    private static class RateLimitBucket {
        private final AtomicInteger counter = new AtomicInteger(0);
        private volatile long windowStart = System.currentTimeMillis();

        public boolean allowRequest() {
            long now = System.currentTimeMillis();
            long elapsed = now - windowStart;

            if (elapsed > TimeUnit.MINUTES.toMillis(1)) {
                synchronized (this) {
                    if (now - windowStart > TimeUnit.MINUTES.toMillis(1)) {
                        windowStart = now;
                        counter.set(0);
                    }
                }
            }

            return counter.incrementAndGet() <= MAX_REQUESTS_PER_MINUTE;
        }
    }
}